<template>
  <div class="container mx-auto py-9">
      <h3 class="font-thin">Hello I'm</h3>
      <h1 class="font-bold text-4xl uppercase pt-1 pb-9 md:text-4xl lg:text-7xl">salvatorecalo</h1>
      <h3 class="text-base md:text-xl lg:text-xl mb-6">
        <span class="typed-text">Junior {{ typeValue }}</span>
        <span class="cursor" :class="{ 'typing': typeStatus}">&nbsp;</span>
      </h3>
      <div class="mb-16 lg:mb-56"><HubButton /></div>
      <Social />
  </div>
</template>

<script>
import HubButton from "./HubButton.vue"
import Social from "./Social.vue"
export default {
    name: 'HubJumbo',
    components: {
    HubButton,
    Social,
},
    data: () => {
      return {
        typeValue: '',
        typeStatus: false,
        typeArray: ['Frontend Web Developer', 'UI Designer', 'Ux Designer', 'App Developer'],
        typingSpeed: 200,
        erasingSpeed: 100,
        newTextDelay: 2000,
        typeArrayIndex: 0,
        charIndex: 0
      }
    },
     methods: {
      typeText() {
        if(this.charIndex < this.typeArray[this.typeArrayIndex].length) {
          if(!this.typeStatus)
            this.typeStatus = true
          this.typeValue += this.typeArray[this.typeArrayIndex].charAt(this.charIndex)
          this.charIndex += 1
          setTimeout(this.typeText, this.typingSpeed)
        }
        else {
          this.typeStatus = false
          setTimeout(this.eraseText, this.newTextDelay)
        }
      },
      eraseText() {
        if(this.charIndex > 0) {
          if(!this.typeStatus)
            this.typeStatus = true
          this.typeValue = this.typeArray[this.typeArrayIndex].substring(0, this.charIndex - 1)
          this.charIndex -= 1
          setTimeout(this.eraseText, this.erasingSpeed)
        }
        else {
          this.typeStatus = false
          this.typeArrayIndex += 1
          if(this.typeArrayIndex >= this.typeArray.length)
            this.typeArrayIndex = 0
          setTimeout(this.typeText, this.typingSpeed + 1000)
        }
      }
    },
    created() {
      setTimeout(this.typeText, this.newTextDelay + 200)
    }
}
</script>

<style>
  span.cursor {
    display: inline-block;
    margin-left: 3px;
    width: 1px;
    background-color: #333;
    animation: cursorBlinked 1s infinite;
  }
  span.cursor.typing { animation: none;}

  @keyframes cursorBlinked {
    49% { background-color: #333;}
    50% { background-color: transparent;}
    99% { background-color: transparent;}
  }
</style>