import Vue from 'vue'
import App from './App.vue'
import router from './router'
import { FontAwesomeIcon } from '@fortawesome/vue-fontawesome'
import { library } from '@fortawesome/fontawesome-svg-core'
import { faCompass, faCode, faStar, faCompassDrafting, faMobileButton } from '@fortawesome/free-solid-svg-icons'
import { faGithub, faTelegram, faInstagram, faLinkedin} from '@fortawesome/free-brands-svg-icons'
library.add(faGithub, faInstagram, faTelegram, faLinkedin, faCode, faCompass, faStar,faCompassDrafting, faMobileButton)
import './index.css'

import 'flowbite'


Vue.component('font-awesome-icon', FontAwesomeIcon)

Vue.config.productionTip = false

new Vue({
  router,
  render: h => h(App)
}).$mount('#app')
